    'VN' => ['footer_note' => "<h2>R ۋىيېتنامدىكى ئېلېكترونلۇق سودا Selldone سودا OS</h2>\n\n<p> ۋېيتنامنىڭ ئاۋات ئاۋات كوچىلىرى ۋە تىنچ مەنزىرىلىرى ئىچىدە ، يېڭى ئېلېكترونلۇق سودا بايانلىرى بارلىققا كەلدى. قىستۇرما سۇپىسى Selldone سودا مەشغۇلات سىستېمىسى ۋېيتناملىق سودىگەرلەرنىڭ رەقەملىك مەۋجۇتلۇقىنى يۇقىرى كۆتۈرۈشىگە سەھنە ھازىرلاپ بەردى. كۆپ خىل مەھسۇلاتلاردىن تارتىپ نۇرغۇنلىغان مۇلازىمەتلەر ، مۇشتەرىلىكلەر ، ھەتتا ھۆججەتلەرگىچە ، بۇ سۇپا چەكسىز پۇرسەتنىڭ چىرىغى. </p>\n\n<h3> رەقەملىك سالاھىيىتىڭىزنى تۇرغۇزۇڭ </h3>\n<p> ۋېيتنام كارخانىلىرىغا نىسبەتەن ، كۈچلۈك تور مەۋجۇتلۇقى ھەممىدىن مۇھىم. Selldone ئارقىلىق ئېلېكترونلۇق سودا ئۆزگىچە تور نامىڭىزغا ئۈزۈل-كېسىل بىرىكىپ ، چىنلىقىغا كاپالەتلىك قىلىدۇ ۋە ھەر بىر زىيارەتچى بىلەن رىشتە ئورنىتىدۇ. </p>\n\n<h3> ئۈنۈمسىز رەقەملىك ئۆتكۈنچى </h3>\n<p> ۋېيتنامدىكى تور دۇكىنىنى قوزغىتىش مېكوڭ دەرياسىغا ئوخشاش سىلىق بولۇشى كېرەك. Selldone ساھىبجامال ، قىستۇرما ۋە قېلىپلارنىڭ مۇرەككەپلىكىنى ئايلىنىپ ئۆتۈپ ، ئاۋارىچىلىقسىز تەڭشەشكە كاپالەتلىك قىلىدۇ. ئۇ ئېلېكترونلۇق سودا ، قايتىدىن بېكىتىلدى. </p>\n\n<h3> ۋېيتنامنىڭ باج مەنزىرىسى </h3> بىلەن ماسلاشتۇرۇلغان\n<p> ۋېيتنامنىڭ باج بەلگىلىمىلىرىنى چوڭقۇر چۈشىنىش ئارقىلىق ، Selldone بىر گەۋدىلەشتۈرۈلگەن باج ھېسابلاش ئىقتىدارلىرى بىلەن تەمىنلەيدۇ. بۇ كارخانىلارنىڭ يوچۇقسىز تىجارەت قىلىشىغا كاپالەتلىك قىلىدۇ ، ھېچقانداق باج ئالماي يەرلىك باج قائىدىسىدە چىڭ تۇرىدۇ. </p>\n\n<h3> ۋېيتنامنىڭ ئۇلۇغۋار ماركىسى </h3>\n<p> خانويدىكى ئىگىلىك تىكلىگۈچىلەردىن Ho Chi Minh شەھىرىدە قۇرۇلغان ماركىلارغىچە ، Selldone كۆلەملەشتۈرۈش ۋە تەرەققىي قىلدۇرۇش ئۈچۈن لايىھەلەنگەن. ئۇ كۆرۈش قۇۋۋىتى بار ۋېيتنام ماركىلىرىنىڭ ئېلېكترونلۇق سودا ھەمراھى. </p>\n\n<h3> سېتىلىشى ئەلالاشتۇرۇلغان </h3>\n<p>Selldone پەقەت بىر سۇپا ئەمەس. ئۇ بىر سېتىش دىناموسى. ۋيېتنام بازىرىغا ماسلاشتۇرۇلغان ، ئۇ ئاددىي تور كۆرگۈچلەرنى سادىق قوللىغۇچىلارغا ئايلاندۇرۇش ئۈچۈن ئىنچىكە تەڭشەلدى. </p>\n\nۋيېتناملىق مال سېتىۋالغۇچىلار ئۈچۈن <h3> قوزغىتىش رىغبەتلەندۈرۈش </h3>\n<ul>\n    <li><b> ھېسابلاش كودى </b> مال سېتىۋېلىش ھەۋەسكارلىرىنى تەبرىكلە